#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char A[100005];
        scanf("%s", A);
        int n = strlen(A);
        long long max = -1;
        for (int i = 0; i < n; i++) {
            char temp[100005];
            strcpy(temp, A);
            temp[i] = '\0';
            memmove(temp + i, temp + i + 1, strlen(temp + i + 1) + 1);
            long long num = atoll(temp);
            if (num % 6 == 0) {
                max = (max > num) ? max : num;
            }
        }
        printf("%lld\n", max);
    }
    return 0;
}

